#include <stdio.h>

struct Rezultat {
    char prezime[20];
    char ime[20];
    int bodovi;
};

int main() {
    FILE *f = fopen("rezultati.txt", "r");
    if (f == NULL) {
        printf("Greska: ne mogu otvoriti rezultati.txt\n");
        return 1;
    }

    struct Rezultat r;
    int ukupno = 0, polozilo = 0;

    int maxBodovi = -1;
    struct Rezultat najbolji;

    while (fscanf(f, "%19s %19s %d", r.prezime, r.ime, &r.bodovi) == 3) {
        ukupno++;
        if (r.bodovi >= 40) polozilo++;

        if (r.bodovi > maxBodovi) {
            maxBodovi = r.bodovi;
            najbolji = r;
        }
    }

    fclose(f);

    if (ukupno == 0) {
        printf("Datoteka je prazna ili format nije ispravan.\n");
        return 0;
    }

    printf("Ukupno studenata: %d\n", ukupno);
    printf("Polozilo (>=40): %d\n", polozilo);
    printf("Najbolji: %s %s (%d)\n", najbolji.prezime, najbolji.ime, najbolji.bodovi);

    return 0;
}
